// Gatekeeper: honeypot -> token -> validation -> dedupe -> canonical payload (form v2, 2026-07-16).
// Every rejection returns bot:true; the respond node sends the SAME success body either way (no oracle).
// Validation rules mirror widget/src/validate.js verbatim.
// Requires NODE_FUNCTION_ALLOW_BUILTIN=crypto,fs.
const crypto = require('crypto');
const fs = require('fs');
const METRICS = '/home/node/.n8n/wgc-metrics.json';
const body = $json.body || {};
const headers = $json.headers || {};

function bump(field) {
  let m = { days: {} };
  try { m = JSON.parse(fs.readFileSync(METRICS, 'utf8')); } catch (e) { /* first run */ }
  const day = new Date().toISOString().slice(0, 10);
  m.days[day] = m.days[day] || { submissions: 0, bots: 0, delivered_api: 0, delivered_email: 0 };
  m.days[day][field] += 1;
  fs.writeFileSync(METRICS, JSON.stringify(m));
}
function reject(reason) { bump('bots'); return [{ json: { bot: true, reason } }]; }

// 1. Honeypot: field named company must be empty (unchanged).
if (typeof body.company === 'string' && body.company.trim() !== '') return reject('honeypot');

// 2. Render token: base64(ts.nonce.hmac), age window 2s-2h (unchanged min-fill-time).
let tokenOk = false;
try {
  const parts = Buffer.from(String(body.token || ''), 'base64').toString('utf8').split('.');
  const ts = parts[0], nonce = parts[1], mac = parts[2] || '';
  const expect = crypto.createHmac('sha256', $env.WGC_HMAC_SECRET).update(ts + '.' + nonce).digest('hex');
  const macBuf = Buffer.from(mac, 'utf8');
  const expBuf = Buffer.from(expect, 'utf8');
  const age = Date.now() - Number(ts);
  tokenOk = macBuf.length === expBuf.length && crypto.timingSafeEqual(macBuf, expBuf) && age >= 2000 && age <= 7200000;
} catch (e) { tokenOk = false; }
if (!tokenOk) return reject('token');

// 3. Validation + normalization (mirror of widget rules, v2).
const errors = [];
function str(v) { return String(v == null ? '' : v).trim(); }
const name = str(body.name);
if (name.length < 1 || name.length > 120) errors.push('name');
const email = str(body.email);
if (email.length > 254 || !/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(email)) errors.push('email');
const rawPhone = str(body.phone);
const digits = rawPhone.replace(/\D/g, '');
let phone = null;
if (rawPhone.startsWith('+') && !rawPhone.startsWith('+1')) phone = null;
else if (rawPhone.startsWith('+')) phone = digits.length === 11 ? '+' + digits : null;
else if (digits.length === 10) phone = '+1' + digits;
else if (digits.length === 11 && digits[0] === '1') phone = '+' + digits;
if (!phone) errors.push('phone');
const zip = str(body.zip);
if (!/^\d{5}$/.test(zip)) errors.push('zip');
let sqft = null;
const sqftStr = str(body.sqft);
const sqftNum = Number(sqftStr);
if (sqftStr === '' || !Number.isInteger(sqftNum) || sqftNum < 300 || sqftNum > 10000) errors.push('sqft');
else sqft = sqftNum;
let bedrooms = null;
const bedroomsStr = str(body.bedrooms);
if (bedroomsStr !== '') {
  if (['2', '3', '4', '5+'].indexOf(bedroomsStr) === -1) errors.push('bedrooms');
  else bedrooms = bedroomsStr;
}
const ebook_opt_in = body.ebook_opt_in === true;
const submission_id = str(body.submission_id);
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{3,4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(submission_id)) errors.push('submission_id');
if (errors.length) return reject('validation:' + errors.join('|'));

// 4. Dedupe: 24h ring buffer in workflow static data (unchanged).
const sd = $getWorkflowStaticData('global');
const now = Date.now();
sd.seen = (sd.seen || []).filter(function (e) { return now - e.t < 86400000; });
if (sd.seen.some(function (e) { return e.id === submission_id; })) return reject('duplicate');
sd.seen.push({ id: submission_id, t: now });

// 5. Canonical payload v2 + server-side consent evidence (ip, ua added here).
const ip = str(headers['x-forwarded-for']).split(',')[0].trim();
const c = body.consent || {};
const payload = {
  submission_id: submission_id,
  name: name,
  email: email,
  phone: phone,
  zip: zip,
  sqft: sqft,
  bedrooms: bedrooms,
  ebook_opt_in: ebook_opt_in,
  source: str(body.source) || 'Website - wgcassetguide',
  consent: {
    implied: true,
    text_version: str(c.text_version) || 'v2-2026-07-16',
    ts: str(c.ts) || new Date().toISOString(),
    ip: ip,
    ua: str(headers['user-agent']).slice(0, 400)
  }
};
bump('submissions');
return [{ json: { bot: false, payload: payload } }];
